import React, { useEffect } from "react";
import itinerariesActions from "../redux/actions/itinerariesActions";
import { useDispatch, useSelector } from "react-redux"
import { useParams } from "react-router-dom";
import { styled } from '@mui/material/styles';
import Card from '@mui/material/Card';
import CardHeader from '@mui/material/CardHeader';
import CardMedia from '@mui/material/CardMedia';
import CardContent from '@mui/material/CardContent';
import CardActions from '@mui/material/CardActions';
import Collapse from '@mui/material/Collapse';
import Avatar from '@mui/material/Avatar';
import IconButton from '@mui/material/IconButton';
import Typography from '@mui/material/Typography';
import { red } from '@mui/material/colors';
import FavoriteIcon from '@mui/icons-material/Favorite';
import ShareIcon from '@mui/icons-material/Share';
import ExpandMoreIcon from '@mui/icons-material/ExpandMore';
import MoreVertIcon from '@mui/icons-material/MoreVert';

let emoji = "💵"

function Itineraries(){

    const {id}= useParams()

    const dispatch = useDispatch()

    useEffect(()=>{
        dispatch(itinerariesActions.findTinFromCity(id))
    },[])

    const itinerary = useSelector(store=>store.itinerariesReducers.itinerary)

    return(
            <div className="itineraries-container">
                    {itinerary.map(itinerary=>(
                        <Card sx={{ maxWidth: 345 }}>
                        <CardHeader
                        avatar={
                            <img src={itinerary.userimage} alt="photo" />
                          }
                          action={
                            <IconButton aria-label="settings">
                              <MoreVertIcon />
                            </IconButton>
                          }
                          title="Shrimp and Chorizo Paella"
                          subheader="September 14, 2016"
                        />
                        <CardMedia
                          component="img"
                          height="194"
                          image="/static/images/cards/paella.jpg"
                          alt="Paella dish"
                        />
                        <CardContent>
                          <Typography variant="body2" color="text.secondary">
                            
                          </Typography>
                        </CardContent>
                        <CardActions disableSpacing>
                          <IconButton aria-label="add to favorites">
                            <FavoriteIcon />
                          </IconButton>
                          <IconButton aria-label="share">
                            <ShareIcon />
                          </IconButton>
                          <ExpandMore
                            expand={expanded}
                            onClick={handleExpandClick}
                            aria-expanded={expanded}
                            aria-label="show more"
                          >
                            <ExpandMoreIcon />
                          </ExpandMore>
                        </CardActions>
                        <Collapse in={expanded} timeout="auto" unmountOnExit>
                          <CardContent>
                            <Typography paragraph>Method:</Typography>
                            <Typography paragraph>
                            
                            </Typography>
                            <Typography paragraph>
                            
                            </Typography>
                            <Typography paragraph>
                            
                            </Typography>
                            <Typography>
                            
                            </Typography>
                          </CardContent>
                        </Collapse>
                      </Card>
                    // <div className="itinerary">
                    //     <div className="photo">
                    //         <img src={itinerary.userimage} alt="photo" />
                    //     </div>
                    //     <div className="personName">
                    //         <p>{itinerary.username}</p>
                    //     </div>
                    //     <div className="itinerary-body">
                    //         <h1>{itinerary.itineraryname}</h1>
                    //         <p>{emoji.repeat(itinerary.price)}</p>
                    //         <p>{itinerary.hashtags}</p>
                    //         <p>{itinerary.time}</p>
                    //         <p>{itinerary.likes}</p>
                    //     </div>
                    // </div>
            ))}
            </div>
    )
}
export default Itineraries
